func (m *dashboardModel) updateFilterHost(key string) tea.Cmd {
	switch key {
	case "esc":
		m.panel = panelMain
		m.menuCursor = 0
	case "j", "down":
		if m.menuCursor < len(m.filterHostChoices)-1 {
			m.menuCursor++
		}
	case "k", "up":
		if m.menuCursor > 0 {
			m.menuCursor--
		}
	case "enter":
		if len(m.filterHostChoices) == 0 {
			m.panel = panelMain
			return nil
		}
		m.tuiHostFilter = m.filterHostChoices[m.menuCursor]
		m.panel = panelMain
		m.menuCursor = 0
		m.loading = true
		return m.refreshCmd()
	}
	return nil
}

