func (m *dashboardModel) handleScrollKeys(key string) bool {
	if m.panel != panelScroll {
		return false
	}
	page := max(1, m.height-6)
	switch key {
	case "esc", "q":
		m.panel = panelMain
		m.scrollLines = nil
		m.scrollOff = 0
		return true
	case "j", "down":
		if m.scrollOff < len(m.scrollLines)-1 {
			m.scrollOff++
		}
		return true
	case "k", "up":
		if m.scrollOff > 0 {
			m.scrollOff--
		}
		return true
	case "ctrl+d", "pgdown":
		m.scrollOff = min(m.scrollOff+page, max(0, len(m.scrollLines)-1))
		return true
	case "ctrl+u", "pgup":
		m.scrollOff = max(0, m.scrollOff-page)
		return true
	case "home", "g":
		m.scrollOff = 0
		return true
	case "end", "G", "shift+g":
		m.scrollOff = max(0, len(m.scrollLines)-1)
		return true
	}
	return false
}

func (m *dashboardModel) sortedHostNames() []string {
	out := make([]string, 0, len(m.cfg.Hosts))
	for k := range m.cfg.Hosts {
		out = append(out, k)
	}
	sort.Strings(out)
	return out
}

func (m *dashboardModel) sortedRepoNames() []string {
	seen := make(map[string]bool)
	for _, r := range m.cfg.Runners {
		if r.Org != "" {
			seen["org:"+r.Org] = true
		} else {
			seen[r.Repo] = true
		}
	}
	out := make([]string, 0, len(seen))
	for r := range seen {
		out = append(out, r)
	}
	sort.Strings(out)
	return out
}

func ensureEnvFile(path string) error {
	dir := filepath.Dir(path)
	if err := os.MkdirAll(dir, 0o700); err != nil {
		return err
	}
	if _, err := os.Stat(path); os.IsNotExist(err) {
		return os.WriteFile(path, []byte(config.EnvFileTemplate), 0o600)
	}
	return nil
}

func tickEvery(d time.Duration) tea.Cmd {
	return func() tea.Msg {
		time.Sleep(d)
		return tickMsg(time.Now())
	}
}

func clampCursor(c, n int) int {
	if n <= 0 {
		return 0
	}
	if c >= n {
		return n - 1
	}
	if c < 0 {
		return 0
	}
	return c
}

func wrapLines(s string, width int) []string {
	if width < 20 {
		width = 80
	}
	var out []string
	for _, line := range strings.Split(s, "\n") {
		rest := line
		for len(rest) > width {
			out = append(out, rest[:width])
			rest = rest[width:]
		}
		out = append(out, rest)
	}
	if len(out) == 0 {
		out = []string{""}
	}
	return out
}

