func (m *dashboardModel) updateFilterRepo(key string) tea.Cmd {
	switch key {
	case "esc":
		m.panel = panelMain
		m.menuCursor = 0
	case "j", "down":
		if m.menuCursor < len(m.filterRepoChoices)-1 {
			m.menuCursor++
		}
	case "k", "up":
		if m.menuCursor > 0 {
